    steps: [
      {
        title: "\ud83d\udcdd \u0625\u062f\u0627\u0631\u0629 \u0627\u0644\u062a\u0633\u062c\u064a\u0644",
        body: "<p>\u0647\u0630\u0647 \u0627\u0644\u0635\u0641\u062d\u0629 \u0644\u0625\u062f\u0627\u0631\u0629 \u062a\u0633\u062c\u064a\u0644 \u0627\u0644\u0637\u0644\u0627\u0628 \u0641\u064a \u0627\u0644\u0645\u0642\u0631\u0631\u0627\u062a:</p><ul><li>\u0625\u0636\u0627\u0641\u0629 \u062a\u0633\u062c\u064a\u0644 \u0641\u0631\u062f\u064a \u0623\u0648 \u062c\u0645\u0627\u0639\u064a</li><li>\u062d\u0630\u0641 \u0623\u0648 \u062a\u0639\u062f\u064a\u0644 \u062a\u0633\u062c\u064a\u0644 \u0642\u0627\u0626\u0645</li><li>\u0627\u0633\u062a\u064a\u0631\u0627\u062f \u0645\u0644\u0641 Excel \u0644\u0644\u062a\u0633\u062c\u064a\u0644 \u0627\u0644\u062c\u0645\u0627\u0639\u064a</li></ul>"
      },
      {
        title: "\ud83d\udce4 \u0627\u0644\u0627\u0633\u062a\u064a\u0631\u0627\u062f \u0627\u0644\u062c\u0645\u0627\u0639\u064a",
        body: "<p>\u0644\u062a\u0633\u062c\u064a\u0644 \u0639\u062f\u062f \u0643\u0628\u064a\u0631 \u0645\u0646 \u0627\u0644\u0637\u0644\u0627\u0628 \u062f\u0641\u0639\u0629 \u0648\u0627\u062d\u062f\u0629:</p><ol><li>\u062d\u0645\u0651\u0644 \u0642\u0627\u0644\u0628 Excel \u0627\u0644\u062c\u0627\u0647\u0632</li><li>\u0627\u0645\u0644\u0623 \u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u0637\u0644\u0627\u0628 (\u0631\u0642\u0645\u060c \u0627\u0633\u0645\u060c \u0645\u0642\u0631\u0631\u060c \u0634\u0639\u0628\u0629)</li><li>\u0627\u0631\u0641\u0639 \u0627\u0644\u0645\u0644\u0641 \u0648\u0627\u0636\u063a\u0637 \u0627\u0633\u062a\u064a\u0631\u0627\u062f</li></ol><p>\u0627\u0644\u0646\u0638\u0627\u0645 \u064a\u0643\u0634\u0641 \u0627\u0644\u062a\u0643\u0631\u0627\u0631\u0627\u062a \u062a\u0644\u0642\u0627\u0626\u064a\u0627\u064b.</p>",
        forRoles: ["head_of_department"]
      },
      {
        title: "\ud83d\udd0d \u0627\u0644\u0628\u062d\u062b \u0648\u0627\u0644\u062a\u0635\u0641\u064a\u0629",
        body: "<p>\u0627\u0633\u062a\u062e\u062f\u0645 \u0623\u062f\u0648\u0627\u062a \u0627\u0644\u0628\u062d\u062b:</p><ul><li>\u0641\u0644\u062a\u0631 \u0628\u0627\u0644\u0645\u0642\u0631\u0631 \u0623\u0648 \u0627\u0644\u0634\u0639\u0628\u0629</li><li>\u0627\u0644\u0628\u062d\u062b \u0628\u0631\u0642\u0645 \u0627\u0644\u0637\u0627\u0644\u0628</li><li>\u062a\u0635\u062f\u064a\u0631 \u0643\u0634\u0641 \u0627\u0644\u062a\u0633\u062c\u064a\u0644 Excel/PDF</li></ul>",
        forRoles: ["head_of_department"]
      }
    ]
