  "department_policy_head": {
    roles: ["head_of_department"],
    title: "\u0633\u064a\u0627\u0633\u0627\u062a \u0627\u0644\u0642\u0633\u0645",
    steps: [
      {
        title: "\ud83d\udcdc \u0645\u0627 \u0647\u064a \u0633\u064a\u0627\u0633\u0627\u062a \u0627\u0644\u0642\u0633\u0645\u061f",
        body: "<p>\u0627\u0644\u0633\u064a\u0627\u0633\u0627\u062a \u0647\u064a \u0642\u0648\u0627\u0639\u062f \u062f\u0627\u062e\u0644\u064a\u0629 \u062a\u0646\u0638\u0645 \u0639\u0645\u0644 \u0627\u0644\u0642\u0633\u0645:</p><ul><li>\u0633\u064a\u0627\u0633\u0629 \u062a\u0648\u0632\u064a\u0639 \u0627\u0644\u0634\u064f\u0639\u0628</li><li>\u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u0625\u0631\u0634\u0627\u062f \u0627\u0644\u0623\u0643\u0627\u062f\u064a\u0645\u064a</li><li>\u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u0627\u0639\u062a\u0630\u0627\u0631 \u0648\u0627\u0644\u062a\u0623\u062c\u064a\u0644</li><li>\u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u062a\u0642\u064a\u064a\u0645</li></ul>"
      },
      {
        title: "\u2795 \u0625\u0636\u0627\u0641\u0629 \u0648\u062a\u0639\u062f\u064a\u0644",
        body: "<p>\u0644\u0625\u0636\u0627\u0641\u0629 \u0633\u064a\u0627\u0633\u0629 \u062c\u062f\u064a\u062f\u0629:</p><ol><li>\u0627\u0636\u063a\u0637 <strong>\u0625\u0636\u0627\u0641\u0629 \u0633\u064a\u0627\u0633\u0629</strong></li><li>\u0627\u0643\u062a\u0628 \u0627\u0644\u0639\u0646\u0648\u0627\u0646 \u0648\u0627\u0644\u0646\u0635</li><li>\u0627\u0636\u063a\u0637 <strong>\u062d\u0641\u0638</strong> (\u062a\u0628\u0642\u0649 \u0645\u0633\u0648\u062f\u0629)</li></ol><p>\u0644\u0644\u062a\u0639\u062f\u064a\u0644: \u0627\u0636\u063a\u0637 \u0639\u0644\u0649 \u0627\u0644\u0633\u064a\u0627\u0633\u0629 \u062b\u0645 <strong>\u062a\u0639\u062f\u064a\u0644</strong>.</p>"
      },
      {
        title: "\ud83d\udce8 \u0625\u0631\u0633\u0627\u0644 \u0644\u0644\u0627\u0639\u062a\u0645\u0627\u062f",
        body: "<p>\u0628\u0639\u062f \u0627\u0644\u0625\u0639\u062f\u0627\u062f\u060c \u0627\u0636\u063a\u0637 <strong>\u0625\u0631\u0633\u0627\u0644 \u0644\u0644\u0627\u0639\u062a\u0645\u0627\u062f</strong> \u0644\u062a\u0631\u0633\u0644\u0647\u0627 \u0644\u0644\u0645\u062f\u064a\u0631.</p><p>\u062d\u0627\u0644\u0627\u062a \u0627\u0644\u0633\u064a\u0627\u0633\u0629:</p><table><tr><td><span class=\"badge bg-secondary\">\u0645\u0633\u0648\u062f\u0629</span></td><td>\u0644\u0645 \u062a\u064f\u0631\u0633\u0644 \u0628\u0639\u062f</td></tr><tr><td><span class=\"badge bg-warning\">\u0628\u0627\u0646\u062a\u0638\u0627\u0631</span></td><td>\u0645\u0631\u0633\u0644\u0629 \u0644\u0644\u0645\u062f\u064a\u0631</td></tr><tr><td><span class=\"badge bg-success\">\u0645\u0639\u062a\u0645\u062f\u0629</span></td><td>\u0648\u0627\u0641\u0642 \u0639\u0644\u064a\u0647\u0627 \u0627\u0644\u0645\u062f\u064a\u0631</td></tr></table>"
      }
    ]
  },

